long long solve(vector<string> cards, string x) {
    char target = x[0];
    vector<string> filtered;

    // Filter cards that contain the target character
    for (const auto& card : cards) {
        if (card[0] == target || card[1] == target) {
            filtered.push_back(card);
        }
    }

    unordered_map<string, int> count;
    for (const auto& card : filtered) {
        count[card]++;
    }

    long long score = 0;

    // Iterate through all unique cards
    for (auto it1 = count.begin(); it1 != count.end(); ++it1) {
        const string& card1 = it1->first;
        int cnt1 = it1->second;

        // Find all cards that are compatible with card1
        for (auto it2 = next(it1); it2 != count.end(); ++it2) {
            const string& card2 = it2->first;
            int cnt2 = it2->second;

            // Check if the two cards are compatible
            int diff = 0;
            if (card1[0] != card2[0]) diff++;
            if (card1[1] != card2[1]) diff++;

            if (diff == 1) {
                int pairs = min(cnt1, cnt2);
                score += pairs;
                it1->second -= pairs;
                it2->second -= pairs;
                cnt1 = it1->second;
                if (cnt1 == 0) break;
            }
        }
    }

    return score;
}
